/// <reference path="../../index.d.ts" />
import type { PublicLitElement as LitElement } from "@arcgis/lumina";

/**
 * @cssproperty [--calcite-autocomplete-background-color] - Specifies the component's background color.
 * @cssproperty [--calcite-autocomplete-border-color] - Specifies the component's border color.
 * @cssproperty [--calcite-autocomplete-text-color] - Specifies the component's text color.
 * @slot  - A slot for adding `calcite-autocomplete-item`s.
 */
export abstract class AutocompleteItemGroup extends LitElement {
  /**
   * Specifies the component's heading text.
   *
   * @required
   */
  accessor heading: string;
  /** Specifies an accessible label for the component. */
  accessor label: any;
  /**
   * Specifies the position of the group in the autocomplete menu.
   *
   * @default 0
   * @internal
   */
  accessor position: number;
}